import{B as e,Q as t,s as n,z as r}from"./chunks/framework.BtoUXlJN.js";var i=JSON.parse(`{"title":"Community","description":"","frontmatter":{},"headers":[],"relativePath":"guide/community.md","filePath":"guide/community.md"}`),a={name:`guide/community.md`};function o(n,i,a,o,s,c){return t(),r(`div`,null,[...i[0]||=[e(`<h1 id="community" tabindex="-1">Community <a class="header-anchor" href="#community" aria-label="Permalink to &quot;Community&quot;">​</a></h1><p>Welcome to the Community guide. This documentation is automatically generated from the latest game features.</p><h2 id="social-media-export" tabindex="-1">Social Media Export <a class="header-anchor" href="#social-media-export" aria-label="Permalink to &quot;Social Media Export&quot;">​</a></h2><p>Share your show cards with the world! The Social Media Export tool generates perfectly formatted match cards for Markdown, Facebook, X (Twitter), and Bluesky. Choose to include match results, segment summaries, and highlighted main events to keep your community engaged and informed.</p><p><img src="/atw-rpg/docs/screenshots/community-show-export.png" alt="Social Media Export"></p><hr><h2 id="joining-a-universe" tabindex="-1">Joining a Universe <a class="header-anchor" href="#joining-a-universe" aria-label="Permalink to &quot;Joining a Universe&quot;">​</a></h2><p>When you follow a universe invite link, you are taken to this page. Existing users can log in and request membership; new users can create a free account and submit their request in one step.</p><p><img src="/atw-rpg/docs/screenshots/universe-join-page.png" alt="Joining a Universe"></p><hr><h2 id="video-walkthroughs" tabindex="-1">Video Walkthroughs <a class="header-anchor" href="#video-walkthroughs" aria-label="Permalink to &quot;Video Walkthroughs&quot;">​</a></h2><h3 id="creating-a-faction" tabindex="-1">Creating a Faction <a class="header-anchor" href="#creating-a-faction" aria-label="Permalink to &quot;Creating a Faction&quot;">​</a></h3><p>New faction appears in the grid — it&#39;s immediately available for member assignment and can be featured in feuds and storylines. Use the Members button to add wrestlers to the roster right away.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/create-faction.mp4" type="video/mp4"></video><hr><h3 id="managing-faction-members" tabindex="-1">Managing Faction Members <a class="header-anchor" href="#managing-faction-members" aria-label="Permalink to &quot;Managing Faction Members&quot;">​</a></h3><p>Wrestler added to the faction roster — the members grid updates instantly. Members can be removed at any time without affecting their match or feud history; faction membership is independent of past results.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/faction-member-management.mp4" type="video/mp4"></video><hr>`,19)]])}var s=n(a,[[`render`,o]]);export{i as __pageData,s as default};